// Function to handle the HTTP request and print its content
func handleRequest() {
	// Define the URL you want to make a request to
	url := "https://api.example.com/data"

	// Create a new HTTP GET request
	resp, err := http.Get(url)
	if err != nil {
		fmt.Printf("Error making the request: %v\n", err)
		return
	}
	defer resp.Body.Close()

	// Check if the request was successful
	if resp.StatusCode != http.StatusOK {
		fmt.Printf("Request failed with status code: %d\n", resp.StatusCode)
		return
	}

	// Read the response body
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Printf("Error reading the response body: %v\n", err)
		return
	}

	// Print the content of the response
	fmt.Printf("Request Content: %s\n", body)
}

func main() {
	handleRequest()
}
